package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;

    @BeforeEach
    void setUp() throws Exception {
        lexerMock = mock(Lexer.class);
        // Use reflection to create CSVParser instance with lexerMock injected
        parser = (CSVParser) java.lang.reflect.Constructor.class
                .cast(CSVParser.class.getDeclaredConstructor(java.io.Reader.class, CSVFormat.class));
        java.lang.reflect.Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(java.io.Reader.class, CSVFormat.class);
        constructor.setAccessible(true);
        parser = constructor.newInstance(new java.io.StringReader(""), CSVFormat.DEFAULT);

        // Inject lexerMock into private final field lexer
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, lexerMock);
    }

    @Test
    void testClose_LexerNotNull_ClosesLexer() throws IOException {
        parser.close();
        verify(lexerMock, times(1)).close();
    }

    @Test
    void testClose_LexerNull_NoException() throws IOException, NoSuchFieldException, IllegalAccessException {
        // Set lexer field to null
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, null);

        parser.close();
        // No exception expected, lexer.close() not called
        verify(lexerMock, never()).close();
    }
}
